#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int half = N/2;
        for (int i = 1; i <= half; ++i) {
            printf("%d ", i);
        }
        for (int i = N; i >= half+1; --i) {
            printf("%d", i);
            if (i != half+1) printf(" ");
        }
        if (T) printf("\n");
    }
    return 0;
}

